Chat Edit: '**Project Structure Generation**

Here's an example of how you can generate a new .NET 8 console application project:

```bash
dotnet new console -o RawrXD.Ollama
cd RawrXD.Ollama
```

Once in the project directory, create the following folders and files:

*   `RawrXD.Ollama/Models`: This folder will hold our C# models.
*   `RawrXD.Ollama/Services`: This folder will hold our C# services.
*   `RawrXD.Ollama/Controllers`: This folder will hold our C# controllers (for HTTP endpoints).
*   `RawrXD.Ollama/Models/OllamaRequestDTO.cs`: This file will define our Ollama request DTO.
*   `RawrXD.Ollama/Services/IOLlamaTransport.cs`: This file will define our IOLlama transport interface.
*   `RawrXD.Ollama/Services/OllamaHttpTransport.cs`: This file will implement our Ollama HTTP transport service.
*   `RawrXD.Ollama/Controllers/RawrXDOllamaController.cs`: This file will handle HTTP requests for the RawrXDOllama endpoint.

Here's an example of what these files might look like:

```csharp
// RawrXD/Ollama/Models/OllamaRequestDTO.cs

namespace RawrXD.Ollama.Models
{
    public class OllamaRequestDTO
    {
        public string Model { get; set; }
        public double Temperature { get; set; }

        public void Handle()
        {
            // Implement request handling logic here
        }
    }
}
```

```csharp
// RawrXD/Ollama/Services/IOLlamaTransport.cs

namespace RawrXD.Ollama.Services
{
    public interface IOllamaTransport
    {
        void Send(OllamaRequestDTO request);
    }
}
```

```csharp
// RawrXD/Ollama/Services/OllamaHttpTransport.cs

using System;
using System.Net.Http;
using System.Threading.Tasks;

namespace RawrXD.Ollama.Services
{
    public class OllamaHttpTransport : IOllamaTransport
    {
        private readonly HttpClient _httpClient;

        public OllamaHttpTransport(HttpClient httpClient)
        {
            _httpClient = httpClient;
        }

        public async Task Send(OllamaRequestDTO request)
        {
            var payload = PayloadSerializer.Serialize(request);
            var response = await _httpClient.PostAsync("/api/generate", new StringContent(payload, System.Text.Encoding.UTF8, "application/json"));

            if (response.IsSuccessStatusCode)
            {
                // Handle successful response
            }
            else
            {
                // Handle failed response
            }
        }
    }
}
```

```csharp
// RawrXD/Ollama/Controllers/RawrXDOllamaController.cs

using System;
using System.Net.Http;
using Microsoft.AspNetCore.Mvc;

namespace RawrXD.Ollama.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class RawrXDOllamaController : ControllerBase
    {
        private readonly IOllamaTransport _transport;

        public RawrXDOllamaController(IOllamaTransport transport)
        {
            _transport = transport;
        }

        [HttpPost]
        public async Task<IActionResult> GenerateCode(OllamaRequestDTO request)
        {
            await _transport.Send(request);
            return Ok();
        }
    }
}
```

